//! parity-cobordism-lm-head — lm_head parity: single `lm_head_only` (full vocab)
//! vs 8 concatenated `lm_head_range` calls (vocab-sharded cobordism path).
//!
//! Usage:
//!   cargo run --release --bin parity-cobordism-lm-head -- /tmp/qwen-coder-7b.knot

use std::env;
use std::time::Instant;

use distributed_inference::loader::KnotWeights;
use distributed_inference::NativeLlamaPipeline;

const SHARDS: [(usize, usize); 8] = [
    (0, 18992),
    (18992, 37984),
    (37984, 56976),
    (56976, 75968),
    (75968, 94960),
    (94960, 113952),
    (113952, 132944),
    (132944, 152064),
];

fn cosine(a: &[f32], b: &[f32]) -> f32 {
    let n = a.len().min(b.len());
    let (mut dot, mut na, mut nb) = (0.0f64, 0.0f64, 0.0f64);
    for i in 0..n {
        let (av, bv) = (a[i] as f64, b[i] as f64);
        dot += av * bv;
        na += av * av;
        nb += bv * bv;
    }
    let d = na.sqrt() * nb.sqrt();
    if d == 0.0 {
        0.0
    } else {
        (dot / d) as f32
    }
}

fn max_abs_delta(a: &[f32], b: &[f32]) -> f32 {
    let n = a.len().min(b.len());
    let mut m = 0.0f32;
    for i in 0..n {
        let d = (a[i] - b[i]).abs();
        if d > m {
            m = d;
        }
    }
    m
}

fn argmax(v: &[f32]) -> usize {
    let mut best = 0;
    let mut bv = f32::NEG_INFINITY;
    for (i, &x) in v.iter().enumerate() {
        if x > bv {
            bv = x;
            best = i;
        }
    }
    best
}

fn top_k(v: &[f32], k: usize) -> Vec<(usize, f32)> {
    let mut ix: Vec<usize> = (0..v.len()).collect();
    ix.sort_by(|&a, &b| v[b].partial_cmp(&v[a]).unwrap_or(std::cmp::Ordering::Equal));
    ix.iter().take(k).map(|&i| (i, v[i])).collect()
}

fn logit_entropy(logits: &[f32]) -> f32 {
    let mx = logits.iter().cloned().fold(f32::NEG_INFINITY, f32::max);
    let se: f64 = logits.iter().map(|&x| ((x - mx) as f64).exp()).sum();
    let lse = (se.ln() + mx as f64) as f32;
    let mut h = 0.0f64;
    for &x in logits {
        let lp = (x - lse) as f64;
        let p = lp.exp();
        if p > 1e-30 {
            h -= p * lp;
        }
    }
    h as f32
}

fn main() -> Result<(), String> {
    let args: Vec<String> = env::args().collect();
    if args.len() < 2 {
        return Err("usage: parity-cobordism-lm-head <knot.path>".into());
    }
    let knot_path = args[1].clone();

    println!("============================================================");
    println!(" parity-cobordism-lm-head");
    println!("   knot: {}", knot_path);
    println!("============================================================");

    let knot = KnotWeights::load(&knot_path)?;
    let cfg = knot.config.as_ref().ok_or("no config block")?;
    let (hidden_dim, vocab_size, num_layers) = (cfg.hidden_dim, cfg.vocab_size, cfg.num_layers);
    println!(
        "[meta] hidden={} layers={} vocab={}",
        hidden_dim, num_layers, vocab_size
    );

    let mut p = NativeLlamaPipeline::from_knot(knot, false, 0.0);

    // Embed a short prompt and run the full transformer.
    // BATCH_CAPACITY is 8 on native — we must chunk the forward pass.
    let tokens: Vec<u32> = vec![
        151644, 8948, 198, 2610, 525, 264, 10950, 17847, 13, 151645, 198, 151644, 872, 198, 9707,
        151645, 198, 151644, 77091, 198,
    ];
    let seq_len = tokens.len();
    let batch_cap = 8usize; // native BATCH_CAPACITY
    println!(
        "\n[1] embed + chunked forward (seq_len={}, batch_cap={})",
        seq_len, batch_cap
    );
    let embed = p.embed_chunk(&tokens, 0)?;

    // Chunk the forward pass through all layers, batch_cap tokens at a time.
    let mut residual = embed.clone();
    for chunk_start in (0..seq_len).step_by(batch_cap) {
        let chunk_len = (seq_len - chunk_start).min(batch_cap);
        let input_offset = chunk_start * hidden_dim;
        let input_end = input_offset + chunk_len * hidden_dim;
        let chunk_input = &residual[input_offset..input_end];
        let chunk_out =
            p.forward_range_chunk(chunk_input, 0, num_layers, chunk_start, chunk_len)?;
        // Write back into the residual buffer.
        residual[input_offset..input_end].copy_from_slice(&chunk_out);
    }
    println!("  residual: {} floats", residual.len());

    // Extract last-token residual (BATCH_CAPACITY limit).
    let last_res = residual[(tokens.len() - 1) * hidden_dim..tokens.len() * hidden_dim].to_vec();
    println!(
        "  last-token first4: [{:.6}, {:.6}, {:.6}, {:.6}]",
        last_res[0], last_res[1], last_res[2], last_res[3]
    );

    // Path A: single lm_head_only
    println!("\n[2] Path A: lm_head_only(seq_len=1)");
    let t = Instant::now();
    let logits_a = p.lm_head_only(&last_res, 1)?;
    println!(
        "  {} logits in {} ms",
        logits_a.len(),
        t.elapsed().as_millis()
    );
    let am_a = argmax(&logits_a);
    let ent_a = logit_entropy(&logits_a);
    println!(
        "  argmax={} logit={:.4} entropy={:.4}",
        am_a, logits_a[am_a], ent_a
    );
    println!("  top5: {:?}", top_k(&logits_a, 5));

    // Path B: 8 sharded lm_head_range calls
    println!("\n[3] Path B: 8 x lm_head_range(seq_len=1)");
    let shard_end = SHARDS[7].1;
    let mut logits_b = vec![0.0f32; shard_end];
    let t = Instant::now();
    for (i, (vs, ve)) in SHARDS.iter().enumerate() {
        let partial = p.lm_head_range(&last_res, 1, *vs, *ve)?;
        let expected = ve - vs;
        let local_am = argmax(&partial);
        println!(
            "  shard{} [{:>6},{:>6}): {} logits, local_argmax={} (global={}), peak={:.4}{}",
            i,
            vs,
            ve,
            partial.len(),
            local_am,
            vs + local_am,
            partial[local_am],
            if partial.len() != expected {
                " !! LENGTH MISMATCH"
            } else {
                ""
            }
        );
        for (j, &v) in partial.iter().enumerate() {
            if vs + j < logits_b.len() {
                logits_b[vs + j] = v;
            }
        }
    }
    println!(
        "  {} logits in {} ms",
        logits_b.len(),
        t.elapsed().as_millis()
    );
    let am_b = argmax(&logits_b);
    let ent_b = logit_entropy(&logits_b);
    println!(
        "  argmax={} logit={:.4} entropy={:.4}",
        am_b, logits_b[am_b], ent_b
    );
    println!("  top5: {:?}", top_k(&logits_b, 5));

    // Compare
    println!(
        "\n[4] Comparison (first {} logits)",
        shard_end.min(logits_a.len())
    );
    let clen = shard_end.min(logits_a.len());
    let (a_s, b_s) = (&logits_a[..clen], &logits_b[..clen]);
    let cos = cosine(a_s, b_s);
    let mxa = max_abs_delta(a_s, b_s);
    println!("  cosine   = {:.10}", cos);
    println!("  max-abs  = {:.10}", mxa);
    println!("  argmax   = A:{} B:{} match={}", am_a, am_b, am_a == am_b);

    // Find worst position
    let mut wi = 0;
    let mut wd = 0.0f32;
    for i in 0..clen {
        let d = (a_s[i] - b_s[i]).abs();
        if d > wd {
            wd = d;
            wi = i;
        }
    }
    if wd > 0.0 {
        println!(
            "  worst at vocab_id={}: A={:.6} B={:.6} delta={:.6}",
            wi, a_s[wi], b_s[wi], wd
        );
        for (i, (vs, ve)) in SHARDS.iter().enumerate() {
            if wi >= *vs && wi < *ve {
                println!("    → shard{} [{}, {})", i, vs, ve);
                break;
            }
        }
    }

    println!("\n============================================================");
    let pass = mxa == 0.0 && am_a == am_b;
    let soft = cos > 0.999999 && am_a == am_b;
    println!(
        " VERDICT: {}",
        if pass {
            "BIT-PERFECT PASS"
        } else if soft {
            "SOFT PASS (FP rounding)"
        } else {
            "FAIL"
        }
    );
    println!("============================================================");
    if !pass && !soft {
        std::process::exit(2);
    }
    Ok(())
}
